import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { Pool } from 'pg';

export interface TenantContext {
  tenantId: string;
  tenantSlug: string;
  userId: string;
  userRole: 'admin_titanio' | 'gestor_cliente' | 'operador';
  email: string;
  permissions: string[];
  database: {
    schema: string;
    connectionString: string;
  };
}

declare global {
  namespace Express {
    interface Request {
      tenant?: TenantContext;
      tenantPool?: Pool;
    }
  }
}

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';
const MASTER_DB_URL = process.env.MASTER_DATABASE_URL;

/**
 * Detecta tenant por:
 * 1. JWT token (Authorization header)
 * 2. Subdomain (sub.example.com)
 * 3. Query param (?tenant=xyz)
 */
export async function tenantDetectionMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    let tenantId: string | null = null;
    let token: string | null = null;

    // 1. Detectar via JWT
    const authHeader = req.headers.authorization;
    if (authHeader?.startsWith('Bearer ')) {
      token = authHeader.substring(7);
      try {
        const decoded = jwt.verify(token, JWT_SECRET) as any;
        tenantId = decoded.tenantId;
        req.tenant = {
          tenantId: decoded.tenantId,
          tenantSlug: decoded.tenantSlug,
          userId: decoded.userId,
          userRole: decoded.userRole,
          email: decoded.email,
          permissions: decoded.permissions || [],
          database: {
            schema: `tenant_${decoded.tenantId}`,
            connectionString: `${MASTER_DB_URL}?currentSchema=tenant_${decoded.tenantId}`,
          },
        };
      } catch (error) {
        return res.status(401).json({ error: 'Invalid token' });
      }
    }

    // 2. Detectar via subdomain (fallback)
    if (!tenantId) {
      const host = req.headers.host || '';
      const subdomain = host.split('.')[0];

      if (subdomain && subdomain !== 'www' && subdomain !== 'api') {
        // Buscar tenant no banco master por slug
        const masterPool = new Pool({ connectionString: MASTER_DB_URL });
        try {
          const result = await masterPool.query(
            'SELECT id, slug FROM tenants WHERE slug = $1 AND is_active = true',
            [subdomain]
          );

          if (result.rows.length === 0) {
            await masterPool.end();
            return res.status(404).json({ error: 'Tenant not found' });
          }

          const tenant = result.rows[0];
          tenantId = tenant.id;

          req.tenant = {
            tenantId: tenant.id,
            tenantSlug: tenant.slug,
            userId: 'anonymous',
            userRole: 'operador',
            email: '',
            permissions: [],
            database: {
              schema: `tenant_${tenant.id}`,
              connectionString: `${MASTER_DB_URL}?currentSchema=tenant_${tenant.id}`,
            },
          };
        } finally {
          await masterPool.end();
        }
      }
    }

    // 3. Detectar via query param (fallback)
    if (!tenantId) {
      const tenantParam = req.query.tenant as string;
      if (tenantParam) {
        const masterPool = new Pool({ connectionString: MASTER_DB_URL });
        try {
          const result = await masterPool.query(
            'SELECT id, slug FROM tenants WHERE id = $1 AND is_active = true',
            [tenantParam]
          );

          if (result.rows.length === 0) {
            await masterPool.end();
            return res.status(404).json({ error: 'Tenant not found' });
          }

          const tenant = result.rows[0];
          req.tenant = {
            tenantId: tenant.id,
            tenantSlug: tenant.slug,
            userId: 'anonymous',
            userRole: 'operador',
            email: '',
            permissions: [],
            database: {
              schema: `tenant_${tenant.id}`,
              connectionString: `${MASTER_DB_URL}?currentSchema=tenant_${tenant.id}`,
            },
          };
        } finally {
          await masterPool.end();
        }
      }
    }

    if (!req.tenant) {
      return res.status(401).json({ error: 'Tenant not detected' });
    }

    // Criar pool especГӯfico do tenant
    req.tenantPool = new Pool({
      connectionString: req.tenant.database.connectionString,
    });

    next();
  } catch (error) {
    console.error('Tenant detection error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
}

/**
 * Middleware para validar tenant context
 */
export function requireTenant(req: Request, res: Response, next: NextFunction): void {
  if (!req.tenant) {
    res.status(401).json({ error: 'Tenant context required' });
    return;
  }
  next();
}

/**
 * Cleanup de recursos do tenant
 */
export async function tenantCleanupMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  res.on('finish', async () => {
    if (req.tenantPool) {
      await req.tenantPool.end().catch(err => 
        console.error('Error closing tenant pool:', err)
      );
    }
  });
  next();
}
